import React, { useState, useRef, useEffect, useMemo } from 'react';
import Fuse from 'fuse.js';
import { motion, AnimatePresence } from 'framer-motion';
import {
  MessageSquare,
  Search,
  History,
  Mic,
  Square,
  Play,
  Sparkles,
  Trash2,
  Calendar,
  ChevronRight,
  Wind,
  BarChart3,
  X,
  LayoutDashboard,
  LogOut
} from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import './index.css';

function App() {
  const [gravando, setGravando] = useState(false);
  const [transcricao, setTranscricao] = useState('');
  const [exercicio, setExercicio] = useState('');
  const [carregando, setCarregando] = useState(false);
  const [historico, setHistorico] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [sessaoAtiva, setSessaoAtiva] = useState(null);
  const [currentView, setCurrentView] = useState('app'); // 'app' or 'dashboard'
  const [showSOS, setShowSOS] = useState(false);
  const [breathingStep, setBreathingStep] = useState('Inspire');

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const audioContextRef = useRef(null);

  // Lógica da animação de respiração e Som de Baixa Frequência (Guadalupe/432Hz)
  useEffect(() => {
    if (!showSOS) {
      if (audioContextRef.current) {
        audioContextRef.current.close().catch(() => { });
        audioContextRef.current = null;
      }
      return;
    }

    // Inicializa Som Relaxante (Frequência Harmônica 432Hz)
    const AudioContext = window.AudioContext || window.webkitAudioContext;
    const ctx = new AudioContext();
    audioContextRef.current = ctx;

    const masterGain = ctx.createGain();
    masterGain.gain.setValueAtTime(0, ctx.currentTime);
    masterGain.gain.linearRampToValueAtTime(0.12, ctx.currentTime + 2); // Fade in suave
    masterGain.connect(ctx.destination);

    // Oscilador Principal (432Hz - Frequência de Cura)
    const osc1 = ctx.createOscillator();
    osc1.type = 'sine';
    osc1.frequency.setValueAtTime(432, ctx.currentTime);

    // Oscilador Secundário (Ligeiro desafino para criar batimento relaxante)
    const osc2 = ctx.createOscillator();
    osc2.type = 'sine';
    osc2.frequency.setValueAtTime(433.5, ctx.currentTime);

    osc1.connect(masterGain);
    osc2.connect(masterGain);

    osc1.start();
    osc2.start();

    // Ciclo de Respiração
    const steps = ['Inspire', 'Segure', 'Expire', 'Segure'];
    let idx = 0;
    const interval = setInterval(() => {
      idx = (idx + 1) % steps.length;
      setBreathingStep(steps[idx]);
    }, 4000);

    return () => {
      clearInterval(interval);
      if (ctx.state !== 'closed') {
        masterGain.gain.linearRampToValueAtTime(0, ctx.currentTime + 1);
        setTimeout(() => ctx.close().catch(() => { }), 1100);
      }
    };
  }, [showSOS]);

  // Carregar histórico ao iniciar
  useEffect(() => {
    fetchHistorico();
  }, []);

  const fetchHistorico = async () => {
    try {
      const resp = await fetch('http://localhost:5000/historico');
      const data = await resp.json();
      setHistorico(data.map(item => ({
        ...item,
        sentimento: item.sentimento || 'Neutro'
      })));
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    }
  };

  const [falando, setFalando] = useState(false);

  // Prepara as vozes do sistema (essencial para Chrome/Brave)
  useEffect(() => {
    const carregarVozes = () => window.speechSynthesis.getVoices();
    carregarVozes();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = carregarVozes;
    }
  }, []);

  const falar = (texto) => {
    if (!texto || !('speechSynthesis' in window)) return;

    window.speechSynthesis.cancel();
    window.speechSynthesis.resume();

    const mensagemPura = texto
      .replace(/SENTIMENTO:.*?\n/g, '')
      .replace(/ABORDAGEM:/g, 'Abordagem teu00f3rica sugerida: ')
      .replace(/LAUDO:/g, 'Laudo de acompanhamento: ')
      .replace(/MAPA:/g, 'Mapa de sensibilidade: ')
      .replace(/ORIENTACAO:/g, 'Orientação técnica: ')
      .replace(/SESSAO:/g, 'Pauta para a próxima sessão: ')
      .replace(/[*#=_\-]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    const chunks = mensagemPura.match(/.{1,200}(?:\s|$)/g) || [mensagemPura];
    let currentChunk = 0;

    const speakNextChunk = () => {
      if (currentChunk >= chunks.length) {
        setFalando(false);
        return;
      }

      const locutor = new SpeechSynthesisUtterance(chunks[currentChunk]);
      const vozes = window.speechSynthesis.getVoices();

      // Prioridade por vozes mais suaves/naturais
      const vozCalma = vozes.find(v => v.name.includes('Natural') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.name.includes('Neural') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.name.includes('Google') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.lang.includes('pt-BR'));

      if (vozCalma) locutor.voice = vozCalma;
      locutor.lang = 'pt-BR';
      locutor.rate = 1.0;   // Velocidade normal
      locutor.pitch = 0.75; // Ainda mais grave para ser menos estridente
      locutor.volume = 0.9;

      locutor.onstart = () => {
        console.log(`Voz ativa: ${vozCalma?.name || 'padrão'} (Pitch Grave)`);
        setFalando(true);
      };

      locutor.onend = () => {
        currentChunk++;
        setTimeout(speakNextChunk, 500); // Pausa mais natural
      };

      locutor.onerror = () => setFalando(false);
      window.speechSynthesis.speak(locutor);
    };

    speakNextChunk();
  };

  const pararDeFalar = () => {
    window.speechSynthesis.cancel();
    setFalando(false);
  };

  const chartData = useMemo(() => {
    return historico.slice().reverse().map(item => ({
      data: item.data.split(' ')[0],
      sentimento: item.sentimento,
      valor: item.sentimento === 'Feliz' ? 3 : item.sentimento === 'Neutro' ? 2 : 1
    }));
  }, [historico]);

  const stats = useMemo(() => {
    return {
      total: historico.length,
      hoje: historico.filter(i => i.data.startsWith(new Date().toLocaleDateString('pt-BR'))).length,
      dominante: historico.length > 0 ? Object.entries(historico.reduce((acc, curr) => {
        acc[curr.sentimento] = (acc[curr.sentimento] || 0) + 1;
        return acc;
      }, {})).sort((a, b) => b[1] - a[1])[0][0] : 'Nenhum'
    };
  }, [historico]);

  const SOSOverlay = () => (
    <motion.div className="sos-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
      <button className="close-sos" onClick={() => setShowSOS(false)}><X size={24} /></button>
      <div className="breathing-container">
        <motion.div className="breathing-circle" animate={{ scale: breathingStep === 'Inspire' || breathingStep === 'Segure' ? 1.5 : 1 }} transition={{ duration: 4, ease: "easeInOut" }}>
          <Wind size={64} className="breathe-icon" />
        </motion.div>
        <h2 className="breathing-text">{breathingStep}</h2>
        <p style={{ opacity: 0.6 }}>Respire fundo, isso vai passar.</p>
      </div>
    </motion.div>
  );

  const DashboardView = () => (
    <div className="dashboard-view">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h2><LayoutDashboard style={{ marginRight: 12, verticalAlign: 'middle' }} /> Painel de Evolução</h2>
        <button className="reset-btn" onClick={() => setCurrentView('app')}>Voltar ao Chat</button>
      </div>
      <div className="stats-grid">
        <div className="stat-card"><span className="stat-value">{stats.total}</span><span className="stat-label">Registros</span></div>
        <div className="stat-card"><span className="stat-value">{stats.hoje}</span><span className="stat-label">Hoje</span></div>
        <div className="stat-card"><span className="stat-value" style={{ fontSize: '1.1rem' }}>{stats.dominante}</span><span className="stat-label">Humor Dominante</span></div>
      </div>
      <div className="chart-container">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={chartData}>
            <defs>
              <linearGradient id="colorVal" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.3} />
                <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" strokeOpacity={0.05} vertical={false} />
            <XAxis dataKey="data" stroke="#64748b" fontSize={10} tickLine={false} />
            <YAxis hide />
            <Tooltip contentStyle={{ background: '#1e293b', border: 'none', borderRadius: '8px', fontSize: '12px' }} />
            <Area type="monotone" dataKey="valor" stroke="#8b5cf6" fillOpacity={1} fill="url(#colorVal)" strokeWidth={2} />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );

  const deleteSessao = async (e, id) => {
    e.stopPropagation();
    if (!window.confirm("Deseja apagar este registro do histórico?")) return;

    try {
      await fetch(`http://localhost:5000/sessao/${id}`, { method: 'DELETE' });
      fetchHistorico();
      if (sessaoAtiva?.id === id) {
        setTranscricao('');
        setExercicio('');
        setSessaoAtiva(null);
      }
    } catch (err) {
      console.error("Erro ao deletar:", err);
    }
  };

  const getSentimentClass = (sentimento) => {
    const s = sentimento.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    return `sentiment-${s}`;
  };

  // Configuração da Busca Dinâmica (Fuse.js)
  const filteredHistorico = useMemo(() => {
    if (!searchTerm) return historico;
    const fuse = new Fuse(historico, {
      keys: ['transcricao', 'exercicio', 'sentimento'],
      threshold: 0.4
    });
    return fuse.search(searchTerm).map(result => result.item);
  }, [historico, searchTerm]);

  const iniciarGravacao = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new window.MediaRecorder(stream);
      audioChunksRef.current = [];
      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.ondataavailable = (e) => audioChunksRef.current.push(e.data);

      mediaRecorder.onstop = async () => {
        setCarregando(true);
        const audioBlob = new Blob(audioChunksRef.current);
        const formData = new FormData();
        formData.append('audio', audioBlob, 'sessao.mp3');

        try {
          const resposta = await fetch('http://localhost:5000/transcribe', {
            method: 'POST',
            body: formData
          });
          const dados = await resposta.json();
          setTranscricao(dados.transcricao);

          const respostaExercicio = await fetch('http://localhost:5000/sugerir-exercicio', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              transcricao: dados.transcricao,
              contexto_anterior: exercicio // Envia o laudo anterior como contexto
            })
          });
          const exercicioData = await respostaExercicio.json();
          setExercicio(exercicioData.exercicio);

          // Falar a resposta automaticamente
          falar(exercicioData.exercicio);

          // Atualizar histórico após nova sessão
          fetchHistorico();
        } catch (error) {
          console.error("Erro ao processar áudio:", error);
          setTranscricao("Erro na conexão com o assistente.");
        } finally {
          setCarregando(false);
        }
      };

      mediaRecorder.start();
      setGravando(true);
      // Ao invés de limpar tudo, mantemos para o contexto se já houver algo
      if (!exercicio) {
        setTranscricao('');
      }
      setSessaoAtiva(null);
      window.speechSynthesis.cancel();
    } catch (err) {
      console.error("Erro ao acessar microfone:", err);
      alert("Por favor, permita o acesso ao microfone.");
    }
  };

  const pararGravacao = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setGravando(false);
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
    }
  };

  const selecionarSessao = (sessao) => {
    setSessaoAtiva(sessao);
    setTranscricao(sessao.transcricao);
    setExercicio(sessao.exercicio);
    falar(sessao.exercicio);
  };

  const formatarAnalise = (texto) => {
    if (!texto) return null;

    const getMatch = (tag) => {
      const regex = new RegExp(`${tag}:([\\s\\S]*?)(?=[A-Z]{4,}:|$)`);
      const match = texto.match(regex);
      return match ? match[1].trim() : null;
    };

    const sections = {
      abordagem: getMatch('ABORDAGEM'),
      laudo: getMatch('LAUDO'),
      mapa: getMatch('MAPA'),
      orientacao: getMatch('ORIENTACAO'),
      sessao: getMatch('SESSAO')
    };

    return (
      <div className="professional-analysis">
        {sections.abordagem && (
          <div className="analysis-section theory-badge">
            <h4 style={{ color: '#ec4899' }}><Sparkles size={14} style={{ marginRight: 8 }} /> Base Teórica</h4>
            <p className="theory-text"><strong>{sections.abordagem}</strong></p>
          </div>
        )}
        {sections.laudo && (
          <div className="analysis-section">
            <h4><ChevronRight size={14} /> Laudo de Acompanhamento</h4>
            <p className="clinical-text">{sections.laudo}</p>
          </div>
        )}

        {sections.mapa && (
          <div className="analysis-section sensitivity-map">
            <h4><ChevronRight size={14} /> Mapa de Sensibilidade</h4>
            <div className="trigger-cloud">
              {sections.mapa.split('\n').map((line, i) => line.trim() && (
                <span key={i} className="trigger-tag">{line.replace(/^[-*]\s*/, '')}</span>
              ))}
            </div>
          </div>
        )}

        {sections.orientacao && (
          <div className="analysis-section orientation">
            <h4><ChevronRight size={14} /> Orientação Técnica</h4>
            <p>{sections.orientacao}</p>
          </div>
        )}

        {sections.sessao && (
          <div className="analysis-section preparation">
            <h4><ChevronRight size={14} /> Pauta para Próxima Sessão</h4>
            <ul>
              {sections.sessao.split('\n').map((line, i) => line.trim() && (
                <li key={i}>{line.replace(/^[-*]\s*/, '')}</li>
              ))}
            </ul>
          </div>
        )}
      </div>
    );
  };

  const copiarParaPsicologo = () => {
    if (!exercicio) return;

    const getMatch = (tag) => {
      const regex = new RegExp(`${tag}:([\\s\\S]*?)(?=[A-Z]{4,}:|$)`);
      const match = exercicio.match(regex);
      return match ? match[1].trim() : null;
    };

    const laudo = getMatch('LAUDO');
    const mapa = getMatch('MAPA');
    const pauta = getMatch('SESSAO');

    const resumo = `
RESUMO CLÍNICO - PSICÓLOGO IA
==============================
DATA: ${sessaoAtiva?.data || new Date().toLocaleString()}

1. MEU DESABAFO:
"${transcricao}"

2. LAUDO DE ACOMPANHAMENTO:
${laudo}

3. MAPA DE SENSIBILIDADE (GATILHOS):
${mapa}

4. PAUTA PARA A PRÓXIMA SESSÃO:
${pauta}

------------------------------
Gerado por Psicólogo IA
    `;
    navigator.clipboard.writeText(resumo);
    alert("Resumo clínico copiado para transferência!");
  };

  return (
    <div className="app-wrapper">
      {/* Sidebar - Busca Dinâmica */}
      <aside className="sidebar">
        <div className="sidebar-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h2 style={{ margin: 0 }}><History size={20} style={{ marginRight: 8 }} /> Histórico</h2>
            <button className="sos-btn-small" onClick={() => setShowSOS(true)} title="Modo SOS / Respiração">
              <Wind size={18} />
            </button>
          </div>
          <button
            className={`nav-btn ${currentView === 'dashboard' ? 'active' : ''}`}
            onClick={() => setCurrentView('dashboard')}
          >
            <BarChart3 size={18} style={{ marginRight: 8 }} /> Ver Evolução
          </button>
          <div className="search-container">
            <Search className="search-icon" size={18} />
            <input
              type="text"
              placeholder="Pesquisar registros..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="history-list">
          {filteredHistorico.map((item) => (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className={`history-item ${sessaoAtiva?.id === item.id ? 'active' : ''}`}
              onClick={() => selecionarSessao(item)}
            >
              <div className="history-item-content">
                <div className="date">
                  {item.data} • <span className={`sentiment-tag ${getSentimentClass(item.sentimento)}`}>{item.sentimento}</span>
                  <button className="delete-btn" onClick={(e) => deleteSessao(e, item.id)}>
                    <Trash2 size={14} />
                  </button>
                </div>
                <div className="preview">{item.transcricao}</div>
              </div>
            </motion.div>
          ))}
          {filteredHistorico.length === 0 && (
            <div className="status-text" style={{ textAlign: 'center', marginTop: '2rem' }}>
              Nenhum registro encontrado
            </div>
          )}
        </div>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        <AnimatePresence>
          {showSOS && <SOSOverlay />}
        </AnimatePresence>

        {currentView === 'dashboard' ? (
          <DashboardView />
        ) : (
          <div className="app-container">
            <header className="header">
              <motion.h1
                initial={{ opacity: 0, y: -20 }}
                animate={{ opacity: 1, y: 0 }}
              >
                Psicólogo IA
              </motion.h1>
              <p className="status-text">Seu suporte profissional e preparação para terapia</p>
            </header>

            <motion.div
              className="main-card"
              layout
            >
              <section className="record-section">
                <button
                  className={`pulse-button ${gravando ? 'recording' : ''}`}
                  onClick={gravando ? pararGravacao : iniciarGravacao}
                  disabled={carregando}
                >
                  {gravando ? <Square size={48} /> : <Mic size={48} />}
                </button>
                <div className="status-container">
                  <span className="status-text">
                    {gravando ? 'Ouvindo desabafo...' : carregando ? 'Atualizando prontuário...' : exercicio ? 'Clique para dar seguimento' : 'Clique para começar a falar'}
                  </span>
                  {exercicio && !carregando && !gravando && (
                    <button className="reset-btn" onClick={() => { setTranscricao(''); setExercicio(''); setSessaoAtiva(null); window.speechSynthesis.cancel(); }}>
                      Novo Atendimento
                    </button>
                  )}
                </div>
              </section>

              <AnimatePresence mode="wait">
                {(transcricao || exercicio || carregando) && (
                  <motion.section
                    className="result-section"
                    initial={{ opacity: 0, opacity: 0 }}
                    animate={{ opacity: 1, opacity: 1 }}
                    exit={{ opacity: 0, opacity: 0 }}
                  >
                    <div className="result-card">
                      <h3><MessageSquare size={14} style={{ marginRight: 8 }} /> Seu Desabafo</h3>
                      <p>{carregando && !transcricao ? <span className="loading-dots">Transcrevendo áudio</span> : transcricao}</p>
                    </div>

                    {(exercicio || carregando) && (
                      <motion.div
                        className="result-card professional-card"
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                      >
                        <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                          <h3 style={{ margin: 0, display: 'flex', alignItems: 'center' }}>
                            <Sparkles size={14} style={{ marginRight: 8 }} /> Análise e Preparação
                          </h3>
                          <div className="card-actions" style={{ display: 'flex', gap: '8px' }}>
                            {exercicio && (
                              <>
                                <button
                                  onClick={copiarParaPsicologo}
                                  className="audio-control-btn"
                                  title="Copiar Resumo para o Psicólogo"
                                  style={{ background: 'rgba(255,255,255,0.1)' }}
                                >
                                  <Calendar size={16} />
                                </button>
                                <button
                                  onClick={falando ? pararDeFalar : () => falar(exercicio)}
                                  className="audio-control-btn"
                                  title={falando ? "Parar áudio" : "Ouvir resposta"}
                                >
                                  {falando ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
                                </button>
                              </>
                            )}
                          </div>
                        </div>
                        <div className="analysis-content">
                          {carregando && !exercicio ? (
                            <span className="loading-dots">Consultando abordagem terapêutica</span>
                          ) : (
                            formatarAnalise(exercicio)
                          )}
                        </div>
                      </motion.div>
                    )}
                  </motion.section>
                )}
              </AnimatePresence>
            </motion.div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
